package dev.harrison.rendacomcarro.attachment.application;
import dev.harrison.rendacomcarro.attachment.domain.*;import dev.harrison.rendacomcarro.attachment.infrastructure.AttachmentRepository;import java.security.MessageDigest;import java.util.*;import org.springframework.core.io.Resource;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.web.multipart.MultipartFile;
@Service public class AttachmentService {private static final long MAX=10L*1024*1024;private static final Set<String> ALLOWED=Set.of("image/jpeg","image/png","application/pdf");private final AttachmentRepository repository;private final FileStorageService storage;public AttachmentService(AttachmentRepository r,FileStorageService s){repository=r;storage=s;}@Transactional public Attachment store(OwnerType type,UUID ownerId,MultipartFile file){if(file==null||file.isEmpty())throw new InvalidAttachmentException("Arquivo vazio");if(file.getSize()>MAX)throw new InvalidAttachmentException("Arquivo excede 10 MiB");if(!ALLOWED.contains(file.getContentType()))throw new InvalidAttachmentException("Tipo de arquivo não permitido");try{byte[] data=file.getBytes();String checksum=HexFormat.of().formatHex(MessageDigest.getInstance("SHA-256").digest(data));String path=storage.store(data);try{return repository.save(Attachment.create(type,ownerId,Optional.ofNullable(file.getOriginalFilename()).orElse("arquivo"),path,file.getContentType(),data.length,checksum));}catch(RuntimeException e){storage.delete(path);throw e;}}catch(InvalidAttachmentException e){throw e;}catch(Exception e){throw new IllegalStateException("Falha ao processar anexo",e);}}@Transactional(readOnly=true)public Attachment get(UUID id){return repository.findById(id).filter(a->a.getStatus().equals("ACTIVE")).orElseThrow(()->new IllegalArgumentException("Anexo não encontrado"));}@Transactional(readOnly=true)public Resource content(UUID id){return storage.load(get(id).getStoredPath());}}
